&lt;h2 id=&#34;itertoolspermutationspr&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#itertoolspermutationspr&#34;&gt;#&lt;/a&gt; itertools.permutations(p,r)&lt;/h2&gt;
